import{_ as a,o as l,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Holding Multiple Roles","description":"","frontmatter":{},"headers":[],"relativePath":"roles/multi-role-users.md","filePath":"roles/multi-role-users.md"}'),t={name:"roles/multi-role-users.md"};function r(n,e,s,h,u,m){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="holding-multiple-roles" tabindex="-1">Holding Multiple Roles <a class="header-anchor" href="#holding-multiple-roles" aria-label="Permalink to &quot;Holding Multiple Roles&quot;">​</a></h1><p>This guide is for people who hold more than one role or more than one assignment at the same time.</p><h2 id="the-main-rule-your-permissions-combine" tabindex="-1">The main rule: your permissions combine <a class="header-anchor" href="#the-main-rule-your-permissions-combine" aria-label="Permalink to &quot;The main rule: your permissions combine&quot;">​</a></h2><p>The app uses a <strong>union of permissions</strong> rule.</p><p>That means:</p><ul><li>your stronger role is <strong>not</strong> weakened by a lesser one</li><li>if one assignment can do something and another cannot, you still keep the stronger ability</li><li>your visible menu is the combined result of everything you hold</li></ul><p>For the plain-language role definitions, see <a href="./overview.html">Roles Explained</a>.</p><h2 id="what-this-looks-like-in-practice" tabindex="-1">What this looks like in practice <a class="header-anchor" href="#what-this-looks-like-in-practice" aria-label="Permalink to &quot;What this looks like in practice&quot;">​</a></h2><p>Examples:</p><ul><li>a <code>King</code> who is also a <code>Co-Leader</code> still keeps kingdom-level access</li><li>someone who leads more than one alliance can switch between them</li><li>someone with kingdom and alliance responsibilities sees the wider set of pages their assignments allow</li></ul><h2 id="my-alliance-selector" tabindex="-1">My Alliance selector <a class="header-anchor" href="#my-alliance-selector" aria-label="Permalink to &quot;My Alliance selector&quot;">​</a></h2><p>If you lead more than one alliance, <strong>My Alliance</strong> shows a selector at the top so you can switch between them.</p><p>Read:</p><ul><li><a href="./../how-to/my-alliance.html">Use the My Alliance Page</a></li></ul><h2 id="the-context-banner-matters-more-for-you" tabindex="-1">The context banner matters more for you <a class="header-anchor" href="#the-context-banner-matters-more-for-you" aria-label="Permalink to &quot;The context banner matters more for you&quot;">​</a></h2><p>When you hold multiple assignments, always watch the context banner near the top of the app.</p><p>It tells you:</p><ul><li>which kingdom you are currently inside</li><li>which alliance you are currently inside</li><li>which role label is active in that context</li></ul><p>If something looks missing, first check that banner before assuming the data is gone.</p><p>See <a href="./../getting-started/navigating.html">Finding Your Way Around</a>.</p><h2 id="good-reading-paths-for-multi-role-users" tabindex="-1">Good reading paths for multi-role users <a class="header-anchor" href="#good-reading-paths-for-multi-role-users" aria-label="Permalink to &quot;Good reading paths for multi-role users&quot;">​</a></h2><p>Start with:</p><ol><li><a href="./overview.html">Roles Explained</a></li><li><a href="./../getting-started/navigating.html">Finding Your Way Around</a></li><li><a href="./../how-to/my-alliance.html">Use the My Alliance Page</a></li><li><a href="./protection-rules.html">Safety Rules You&#39;ll Run Into</a></li></ol><p>Then add the role guides that match the roles you actually hold:</p><ul><li><a href="./supreme-admin.html">Supreme Admin Guide</a></li><li><a href="./king.html">King Guide</a></li><li><a href="./alliance-leader.html">Alliance Leader Guide</a></li><li><a href="./co-leader.html">Co-Leader Guide</a></li></ul>',25)])])}const p=a(t,[["render",r]]);export{d as __pageData,p as default};
